steps.message:
Multi-patch alpine-provision.expect (2 edits)
2  2  | set timeout 600
3  3  | log_user 1
4  4  | 
   5  |+proc wait_prompt {} {
   6  |+  expect {
   7  |+    -re {(^|\r|\n).+# } { return 0 }
   8  |+    timeout { puts "Timed out waiting for shell prompt"; exit 1 }
   9  |+    eof { puts "QEMU exited unexpectedly"; exit 1 }
   10 |+  }
   11 |+}
   12 |+
5  13 | set qemu_cmd [list qemu-system-x86_64 \
6  14 |   -m 1024 \
7  15 |   -smp 2 \
...
22 30 | expect {
23 31 |   -re {localhost login: ?$} {}
24 32 |   timeout {puts "Timed out waiting for login prompt"; exit 1}
   33 |+  eof {puts "QEMU exited before login prompt"; exit 1}
25 34 | }
26 35 | send -- "root\r"
27    |-
   36 |+wait_prompt
   37 |+send -- "export TERM=dumb PS1='PROMPT# '\r"
28 38 | expect {
29    |-  -re {~# $} {}
30    |-  -re {localhost:~# $} {}
31    |-  timeout {puts "Timed out waiting for root shell"; exit 1}
   39 |+  -re {PROMPT# } {}
   40 |+  timeout {puts "Timed out setting shell prompt"; exit 1}
32 41 | }
33 42 | 
34 43 | send -- "setup-interfaces -a >/tmp/setup-interfaces.log 2>&1 || true\r"
35    |-expect -re {# $}
   44 |+wait_prompt
36 45 | send -- "udhcpc -i eth0 >/tmp/udhcpc.log 2>&1 || true\r"
37    |-expect -re {# $}
   46 |+wait_prompt
38 47 | send -- "printf '/media/cdrom/apks\n' > /etc/apk/repositories\r"
39    |-expect -re {# $}
   48 |+wait_prompt
40 49 | send -- "apk update >/tmp/apk-update.log 2>&1\r"
41    |-expect -re {# $}
   50 |+wait_prompt
42 51 | send -- "apk add openssh >/tmp/apk-add.log 2>&1\r"
43    |-expect -re {# $}
   52 |+wait_prompt
44 53 | send -- "mkdir -p /run/openrc && touch /run/openrc/softlevel\r"
45    |-expect -re {# $}
   54 |+wait_prompt
46 55 | send -- "ssh-keygen -A >/tmp/ssh-keygen.log 2>&1\r"
47    |-expect -re {# $}
   56 |+wait_prompt
48 57 | send -- "if grep -q '^#\\?PermitRootLogin' /etc/ssh/sshd_config; then sed -i 's/^#\\?PermitRootLogin.*/PermitRootLogin yes/' /etc/ssh/sshd_config; else echo 'PermitRootLogin yes' >> /etc/ssh/sshd_config; fi\r"
49    |-expect -re {# $}
   58 |+wait_prompt
50 59 | send -- "if grep -q '^#\\?PasswordAuthentication' /etc/ssh/sshd_config; then sed -i 's/^#\\?PasswordAuthentication.*/PasswordAuthentication yes/' /etc/ssh/sshd_config; else echo 'PasswordAuthentication yes' >> /etc/ssh/sshd_config; fi\r"
51    |-expect -re {# $}
   60 |+wait_prompt
52 61 | send -- "printf 'password123\npassword123\n' | passwd root >/tmp/passwd.log 2>&1\r"
53    |-expect -re {# $}
   62 |+wait_prompt
54 63 | send -- "rc-update add sshd default >/tmp/rc-update.log 2>&1 || true\r"
55    |-expect -re {# $}
   64 |+wait_prompt
56 65 | send -- "rc-service sshd restart >/tmp/sshd.log 2>&1 || /usr/sbin/sshd\r"
57    |-expect -re {# $}
   66 |+wait_prompt
58 67 | send -- "echo PROVISION_DONE\r"
59 68 | expect {
60 69 |   -re {PROVISION_DONE} {}
